const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const redis = require('redis');

const app = express();
app.use(bodyParser.json());

const redisClient = redis.createClient();

// Generate a secure random refresh token
function generateRefreshToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Store the refresh token in Redis with a long TTL (1 year)
async function storeRefreshToken(userId, refreshToken) {
  const ttl = 365 * 24 * 60 * 60; // 1 year in seconds
  await redisClient.setex(`refresh_token:${userId}`, ttl, refreshToken);
}

// Retrieve the refresh token from Redis
async function getRefreshToken(userId) {
  return await redisClient.get(`refresh_token:${userId}`);
}

